#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream file("text.txt"); // replace "text.txt" with your file name
    std::string wordToFind = "word"; // replace "word" with the word you want to find
    int count = 0;
    std::string word;

    if (!file) {
        std::cout << "Unable to open file\n";
        return 1; // return with error code
    }

    while (file >> word) {
        if (word == wordToFind) {
            count++;
        }
    }

    std::cout << "The word '" << wordToFind << "' appears " << count << " times in the file.\n";

    file.close();

    return 0;
}
```

